mapper.select:
SELECT c.id, c.name, c.slug, c.description, c.cover_image, c.article_count, c.read_count, c.sort_order, c.status, c.create_time, c.update_time, c.user_id, u.nickname, u.avatar FROM `column` c LEFT JOIN user u ON c.user_id = u.id WHERE c.deleted = 0 AND c.status = 1
AND (c.name LIKE CONCAT('%', #{query.keyword}, '%') OR c.description LIKE CONCAT('%', #{query.keyword}, '%'))
AND c.user_id = #{query.userId}
ORDER BY c.sort_order ASC, c.create_time DESC LIMIT #{offset}, #{pageSize}

mapper.update:
UPDATE `column`
name = #{name}, slug = #{slug}, description = #{description}, cover_image = #{coverImage}, sort_order = #{sortOrder}, update_time = #{updateTime}
WHERE id = #{id}

mapper.select:
SELECT COUNT(*) FROM `column` WHERE deleted = 0 AND status = 1
AND (name LIKE CONCAT('%', #{query.keyword}, '%') OR description LIKE CONCAT('%', #{query.keyword}, '%'))
AND user_id = #{query.userId}
